#!/usr/bin/perl

use strict;
use warnings;

print "Content-type: text/html\n\n";
my $redirect_url = $ENV{'QUERY_STRING'} =~ m/next=(.*)/ ? $1 : '';
if ($redirect_url) {
    print "Location $redirect_url\n\n";
}
exit(0);